package com.chaobo.scm.supplier.infrastructure.persistence.contract;

import org.apache.ibatis.annotations.*;import java.math.BigDecimal;import java.time.LocalDate;import java.util.List;
@Mapper public interface PriceAgreementQueryMapper {record Header(long id,String ref,long contractId,long quoteId,long supplierId,String currency,LocalDate from,LocalDate to,int status,int version){}record Line(String sku,BigDecimal price,BigDecimal tax,BigDecimal moq,int days){}@Select("SELECT agreement_id id,agreement_ref ref,contract_id contractId,quote_id quoteId,supplier_id supplierId,currency,effective_from `from`,effective_to `to`,agreement_status status,source_contract_version version FROM sup_price_agreement WHERE agreement_id=#{id}")Header find(long id);@Select("SELECT sku_code sku,unit_price price,tax_rate tax,moq,delivery_days days FROM sup_price_agreement_line WHERE agreement_id=#{id}")List<Line> lines(long id);@Select("<script>SELECT COUNT(DISTINCT a.agreement_id) FROM sup_price_agreement a LEFT JOIN sup_price_agreement_line l ON l.agreement_id=a.agreement_id WHERE 1=1 <if test=\"supplierId != null\">AND a.supplier_id=#{supplierId}</if><if test=\"skuCode != null and skuCode != ''\">AND l.sku_code=#{skuCode}</if></script>")long count(@Param("supplierId")Long supplierId,@Param("skuCode")String skuCode);@Select("<script>SELECT DISTINCT a.agreement_id id,a.agreement_ref ref,a.contract_id contractId,a.quote_id quoteId,a.supplier_id supplierId,a.currency,a.effective_from `from`,a.effective_to `to`,a.agreement_status status,a.source_contract_version version FROM sup_price_agreement a LEFT JOIN sup_price_agreement_line l ON l.agreement_id=a.agreement_id WHERE 1=1 <if test=\"supplierId != null\">AND a.supplier_id=#{supplierId}</if><if test=\"skuCode != null and skuCode != ''\">AND l.sku_code=#{skuCode}</if> ORDER BY a.updated_at DESC LIMIT #{offset},#{size}</script>")List<Header> page(@Param("supplierId")Long supplierId,@Param("skuCode")String skuCode,@Param("offset")int offset,@Param("size")int size);@Select("SELECT l.sku_code sku,l.unit_price price,l.tax_rate tax,l.moq,l.delivery_days days FROM sup_price_agreement a JOIN sup_price_agreement_line l ON l.agreement_id=a.agreement_id WHERE a.supplier_id=#{supplierId} AND l.sku_code=#{skuCode} AND a.currency=#{currency} AND a.agreement_status=1 AND a.effective_from<=#{date} AND a.effective_to>=#{date} ORDER BY a.effective_from DESC LIMIT 1")Line activeLine(@Param("supplierId")long supplierId,@Param("skuCode")String skuCode,@Param("currency")String currency,@Param("date")LocalDate date);}
